class Solution {
public:
    vector<int> findSubstring(string s, vector<string>& words) {
        if (s.empty() || words.empty()) return {};
        int wordLen = words[0].size(), wordNum = words.size(), totalLen = wordLen * wordNum;
        unordered_map<string, int> wordCount;
        for (const string& word : words) ++wordCount[word];
        vector<int> res;
        for (int i = 0; i <= s.size() - totalLen; ++i) {
            unordered_map<string, int> seen;
            for (int j = 0; j < wordNum; ++j) {
                int k = i + j * wordLen;
                string tmp = s.substr(k, wordLen);
                if (!wordCount.count(tmp) || ++seen[tmp] > wordCount[tmp]) break;
                if (j + 1 == wordNum) res.push_back(i);
            }
        }
        return res;
    }
};
